/* adm-item-itemunit-sql-oracle.xml - selectItemUnit */ #{GRIDPAGING_ROWNUMTYPE_TOP} SELECT A.* FROM ( SELECT '0' AS CHK ,A.OWKEY ,C.OWNM ,A.ICUNITKEY ,B.ICUNITTYPE ,B.ICUNITQTY ,A.CLOSDATE ,B.INSERTDATE ,B.UPDATEDATE ,B.INSERTURKEY ,B.UPDATEURKEY ,B.ICUNITORDER ,IC.ICNM ,IC.ICKEY ,IC.SPEC ,IC.IFYN FROM TADMIN_MST_ICUT A INNER JOIN TADMIN_MST_ICUTXTYPE B ON A.OWKEY = B.OWKEY AND A.ICUNITKEY = B.ICUNITKEY INNER JOIN TADMIN_MST_OW C ON A.OWKEY = C.OWKEY LEFT OUTER JOIN TADMIN_MST_IC IC ON A.OWKEY = IC.OWKEY AND A.ICUNITKEY = IC.ICUNITKEY WHERE IC.DELYN ='N' ) A
WHERE #{SEARCH_CONDITION}
ORDER BY #{colName} DESC
ORDER BY #{colName} ASC
ORDER BY UPDATEDATE DESC , ICUNITKEY ASC
#{GRIDPAGING_ROWNUMTYPE_BOTTOM}

/* adm-item-itemunit-sql-oracle.xml - selectTAdminMstIcutxtypexctCount */
SELECT 	COUNT(1) 
  FROM 	TADMIN_MST_ICUTXTYPEXCT
 WHERE 	CTKEY = #{ctkey}
   AND  OWKEY = #{owkey}
   AND	ICUNITKEY = #{icunitkey}
   AND	ICUNITTYPE = #{icunittype}

