/* adm-item-itemunit-sql-oracle.xml - updateTAdminMstIcut */
UPDATE 	TADMIN_MST_ICUT
   SET 	CLOSDATE = SUBSTR(#{closdate}, 0, 14)
	  	,UPDATEDATE = #{sysdate}
	  	,UPDATEURKEY = #{surkey}
 WHERE  OWKEY = #{owkey}
   AND	ICUNITKEY = #{icunitkey}

