mapper.insert:
/* adm-item-itemunit-sql-oracle.xml - mergeTAdminMstIcuttype */
/* Converted from: MERGE INTO TADMIN_MST_ICUTXTYPE ON CONFLICT */
INSERT INTO TADMIN_MST_ICUTXTYPE (
			OWKEY, ICUNITKEY, ICUNITTYPE, ICUNITORDER, ICUNITQTY
			,INSERTDATE, INSERTURKEY, UPDATEDATE, UPDATEURKEY
			,LENGTH, WIDTH, HEIGHT, WEIGHT, VOL, SIZEUNIT, VOLUNIT, WEIGHTUNIT
		) VALUES (
			 #{owkey}, #{icunitkey}, #{icunittype}, #{icunitorder}, #{icunitqty}
			,#{sysdate}, #{surkey}, #{sysdate}, #{surkey}
			,#{lengthunit}, #{widthunit}, #{heightunit}, #{weight}, #{vol}, #{sizeunit}, #{volunit}, 'G'
		)
ON CONFLICT (OWKEY, ICUNITKEY, ICUNITTYPE) DO UPDATE SET
			ICUNITQTY 	= #{icunitqty}
			, ICUNITORDER 	= #{icunitorder}
			, LENGTH    	= #{lengthunit}
			, WIDTH	    = #{widthunit}
			, HEIGHT 		= #{heightunit}
			, WEIGHT 		= #{weight}
			, VOL 		= #{vol}
			, WEIGHTUNIT  = 'G'
			, UPDATEURKEY = #{surkey}
			, UPDATEDATE  = #{sysdate}

/* adm-item-itemunit-sql-oracle.xml - mergeTAdminMstIcutxtypexct */
/* Converted from: MERGE INTO TADMIN_MST_ICUTXTYPEXCT ON CONFLICT */
INSERT INTO TADMIN_MST_ICUTXTYPEXCT (
			 OWKEY, ICUNITKEY, ICUNITTYPE, CTKEY
			,INSERTDATE, INSERTURKEY, UPDATEDATE, UPDATEURKEY
		) VALUES (
			 #{owkey}, #{icunitkey}, #{icunittype}, #{ctkey}
			,#{sysdate}, #{surkey}, #{sysdate}, #{surkey}
		)
ON CONFLICT (OWKEY, CTKEY, ICUNITKEY, ICUNITTYPE) DO UPDATE SET
			UPDATEDATE	= #{sysdate}
			,UPDATEURKEY 	= #{surkey}
